--这个方法根据秒数返回标准的时间格式 例如04:08:42
local function SecondToFmtString(self, secs)
	secs = math.floor(secs or 0)  -- 确保 secs 是整数

	local day = math.floor(secs / OneDayTime)
	local hour = math.floor((secs % OneDayTime) / 3600)
	local minute = math.floor((secs % 3600) / 60)
	local second = math.floor(secs % 60)

	-- 强制转换为整数，避免格式化时的类型错误
	hour = math.floor(hour)
	minute = math.floor(minute)
	second = math.floor(second)

	if day > 0 then
		-- 如果有天数，输出 "x d HH:MM:SS" 格式
		return string.format("%dd\u{00A0}%02d:%02d:%02d", day, hour, minute, second)
	else
		-- 如果没有天数，输出 "HH:MM:SS" 格式
		return string.format("%02d:%02d:%02d", hour, minute, second)
	end
end

