local function CheckIfIsSameWeek(self, smallMs)
    local serverT = self:GetServerTime()
    local intervalMs = math.abs(serverT - smallMs)
    if intervalMs > (7 * 24 * 60 * 60 * 1000) then
        return false
    else
        local smallS = math.modf(smallMs / 1000)
        local ServerS = math.modf(serverT / 1000)
        local isSameDay = self:IsSameDayForServer(smallS, ServerS)
        if isSameDay then
            return true
        else
            local weekIndex1 = self:GetWeekdayIndex(smallMs)
            local weekIndex2 = self:GetWeekdayIndex(serverT)
            if smallMs<serverT then
                return weekIndex2 > weekIndex1
            else
                return weekIndex2 < weekIndex1
            end

        end
    end
end

function UITimeManager:GetWeekdayIndex(timeMs)
    --local serverT = self:GetServerTime()
    --local timeStamp = timeMs / 1000
    local timeStamp = math.modf((timeMs + self.changeDeltaTime) / 1000)
    --local timeStamp =  math.modf(timeStamp)-- (serverT+self.changeDeltaTime)/1000
    local newDate = os.date("!*t", timeStamp)
    local weekIndex = self:GetWeekDay(newDate.year, newDate.month, newDate.day)
    return weekIndex
end

--周x
function UITimeManager:GetWeekDay(y,m,d)
    if m == 1 or m == 2 then
        m = m + 12
        y = y - 1
    end
    local m1,_ = math.modf(3 * (m + 1) / 5)
    local m2,_ = math.modf(y / 4)
    local m3,_ = math.modf(y / 100)
    local m4,_ = math.modf(y / 400)

    local iWeek = (d + 2 * m + m1 + y + m2 - m3  + m4 ) % 7
    
    return weekTab[tostring(iWeek)]
end

local function GetNextWeekDay(self, day)
    local curTime = self:GetServerTime()
    --curTime = math.modf(curTime+self.changeDeltaTime)
    local curWeekday = self:GetWeekdayIndex(curTime)
    local dayOffset = day > curWeekday and day - curWeekday or day + 7 - curWeekday
    local targetDay = curTime + dayOffset * 24 * 3600000
    local targetTs = self:GetTodayZeroServerTime(math.modf(targetDay / 1000))
    return math.modf(targetTs * 1000)
end

--获取当前星期的其中一天,day代表星期几
local function GetCurWeekDay(self,day)
    local curTime = self:GetServerTime()
    --curTime = math.modf(curTime+self.changeDeltaTime)
    local curWeekday = self:GetWeekdayIndex(curTime)
    local dayOffset = day - curWeekday --day > curWeekday and day - curWeekday or day + 7 - curWeekday
    local targetDay = curTime + dayOffset * 24 * 3600000
    local targetTs = self:GetTodayZeroServerTime(math.modf(targetDay / 1000))
    return math.modf(targetTs * 1000)
end

function UITimeManager:GetWeekOffestOfOpenDay(cur_time)
    local open_time = toInt(LuaEntry.Player.openServerTime / 1000)
    local timeTab = os.date("*t",open_time)
	local openZero = open_time - timeTab.hour * OneHourTime - timeTab.min * 60
    open_time = openZero
    -- cur_time当前时间
    -- local current_time = os.time()
    
    -- 计算时间差（秒）
    local time_diff = cur_time - open_time
    
    -- 计算天数差
    local day_diff = math.ceil(time_diff / (24 * 60 * 60))
    local open_day_of_week = tonumber(os.date("%w", open_time))
    if open_day_of_week == 0 then open_day_of_week = 7 end -- 将周日从 0 转换为 1
    local current_day_of_week = tonumber(os.date("%w", cur_time))
    if current_day_of_week == 0 then current_day_of_week = 7 end -- 将周日从 0 转换为 1
    -- 计算周数差和周几
    local week_diff = math.ceil((day_diff + open_day_of_week-1) / 7)
    return week_diff,current_day_of_week
end

local function GetFormattedTimeMs(self, milliSecond)
    return self:GetFormattedTime(milliSecond / 1000)
end

local function GetFormattedTime(self, second)
    local s = math.floor(second)
    local d = s // 86400
    s = s % 86400
    local h = s // 3600
    s = s % 3600
    local m = s // 60
    s = s % 60
    if d > 0 then
        return Localization:GetString("100036", d, h)
    elseif h > 0 then
        return Localization:GetString("100037", h, m)
    else
        return string.format("%02d:%02d", m, s)
    end
end

-- 返回ms，毫秒！
function UITimeManager:GetLocalTime()
    local nowTime = socket.gettime() * 1000
    return nowTime
end


function UITimeManager:FmtStringToMilliSecond(timeStr)

     local datelist = string.split(timeStr, " ");
     local datebegin = string.string2array_i(datelist[1], "-");
     local dateend = string.string2array_i(datelist[2], ":");
     local day = datebegin[3] or 1;
     local month = datebegin[2] or 1;
     local year = datebegin[1] or 1975;
     local hour = dateend[1] or 0;
     local minute = dateend[2] or 0;
     local second = dateend[3] or 0;

     -- 转换为时间戳
     local timestamp = os.time({day = day, month = month, year = year, hour = hour, minute = minute, second = second})
     return timestamp * 1000
end

--服务器时间格式化
function UITimeManager:TimeStampToDayTbForServer(timeStamp)
    local format = UITimeManager:GetInstance():TimeStampToTimeForServerFormat(timeStamp)
    return format.year,format.month,format.day
end

--仅显示时：分
function UITimeManager:TimeStampToTimeForServerHourAndMinute(timeStamp)
    local format = self:TimeStampToTimeForServerFormat(timeStamp)
    local format_time = string.format("%02d:%02d",format.hour,format.min)
    return format_time
end

--仅显示时：分
function UITimeManager:TimeStampToTimeForLocalHourAndMinute(timeStamp)
    local time = math.modf(timeStamp/1000) --Lua的除法结果是保留小数的,先确保结果为整数
    local format = os.date("*t", time)
    local format_time = string.format("%02d:%02d",format.hour,format.min)
    return format_time
end

function UITimeManager:GetOpenServerDays()
    local serverTimeS = self:GetServerSeconds()
    local todayZero = self:GetTodayZeroServerTime(serverTimeS)
    local openServerDays = math.ceil((todayZero * 1000 - LuaEntry.Player.openServerTime) / OneDayTimeMS) + 1
    local season = DataCenter.SeasonDataManager:GetSeason() or 0
    if season > 0 then
        openServerDays = DataCenter.SeasonDataManager:GetSeasonDurationDay() + 1
    end
    return openServerDays
end

-- 将毫秒转换为天数，向上取整
function UITimeManager: MilliSecondToDays(milliSecond)
    local secs = math.ceil(milliSecond / 1000)  -- 毫秒转秒，向上取整
    local days = math.ceil(secs / OneDayTime)   -- 秒转天，向上取整
    return days
end

